import{Page}from"../core/pagination.js";import{APIResource}from"../core/resource.js";import{path}from"../internal/utils/path.js";var Models=class extends APIResource{retrieve(e,t){return this._client.get(path`/models/${e}`,{...t,__security:{bearerAuth:!0}})}list(t){return this._client.getAPIList(`/models`,Page,{...t,__security:{bearerAuth:!0}})}delete(e,t){return this._client.delete(path`/models/${e}`,{...t,__security:{bearerAuth:!0}})}};export{Models};